#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""GEO/ICP niche tiering (exit-0-safe, bounded). Tags atlas.business.icp_tier:
A = high-value pro-services + prioritized GEO niches (attorneys, dentists, med spas,
derm/cosmetic, CPAs, real estate, insurance, chiro, optometry, vets, HVAC, plumbers,
electricians, landscaping, roofing); B = mid-value local services (beauty/wellness,
salons/spas, fitness, auto repair/detailing, pest control, cleaning, remodeling, etc.);
C = everything else. Bounded UPDATE (statement_timeout) so it can never wedge the applier.
Publishes geo-rank.json with tier counts, prospect(qa PASS) mix, and the daily ICP-mix %."""
import os,sys,json,time,subprocess,base64,urllib.request,urllib.error
A=r"attorney|lawyer|law firm|legal serv|dentist|dental|orthodont|endodont|med ?spa|dermatolog|cosmetic|plastic surg|cpa|accounting|accountant|bookkeep|tax prep|real estate|realtor|realty|insurance agen|insurance brok|chiropract|optometr|veterinar|hvac|heating|air condition|plumb|electrician|electrical contract|landscap|lawn care|roofing|roofer"
B=r"beauty|wellness|salon|barber|fitness|gym|pilates| yoga|auto repair|auto detail|detailing|body shop|pest control|exterminat|cleaning|janitorial| maid|remodel|renovation|general contract|hardscap|pool service|garage door|locksmith|towing|urgent care|clinic|physical therap|marketing agenc|web design|day spa"
def psql(q,t=120):
    for pre in (["sudo","-u","postgres","psql","tuanichat_atlas","-tAc",q],
                ["su","-s","/bin/sh","postgres","-c","psql tuanichat_atlas -tAc \"%s\""%q.replace('"','\\"')]):
        try:
            r=subprocess.run(pre,capture_output=True,text=True,timeout=t)
            if r.returncode==0: return r.stdout.strip()
        except Exception: pass
    return "ERR"
out={"kind":"geo_rank","ts":int(time.time())}
try:
    psql("ALTER TABLE atlas.business ADD COLUMN IF NOT EXISTS icp_tier text")
    # bounded tiering of up-to 400k untiered rows (statement_timeout guards runtime)
    upd=("SET statement_timeout='90s'; "
         "UPDATE atlas.business b SET icp_tier=CASE "
         "WHEN lower(coalesce(b.category,'')||' '||coalesce(b.name,'')) ~ '%s' THEN 'A' "
         "WHEN lower(coalesce(b.category,'')||' '||coalesce(b.name,'')) ~ '%s' THEN 'B' "
         "ELSE 'C' END "
         "WHERE b.id IN (SELECT id FROM atlas.business WHERE icp_tier IS NULL LIMIT 400000)"%(A,B))
    out["update"]=psql(upd,t=120)
    out["tier_counts"]=psql("SELECT coalesce(icp_tier,'(untiered)')||':'||count(*) FROM atlas.business GROUP BY icp_tier ORDER BY 2 DESC")
    out["prospect_tier_mix"]=psql("SELECT coalesce(icp_tier,'(none)')||':'||count(*) FROM atlas.business WHERE qa_status='PASS' GROUP BY icp_tier ORDER BY 2 DESC")
    out["A_share_of_prospects"]=psql("SELECT round(100.0*count(*) FILTER (WHERE icp_tier='A')/greatest(count(*),1),1)||'%' FROM atlas.business WHERE qa_status='PASS'")
except Exception as e:
    out["error"]=str(e)
def envf(p):
    d={}
    try:
        for ln in open(p):
            ln=ln.strip()
            if ln.startswith('export '): ln=ln[7:]
            if '=' in ln and not ln.startswith('#'):
                k,v=ln.split('=',1); d[k.strip()]=v.strip().strip('"').strip("'")
    except Exception: pass
    return d
try:
    env=envf("/etc/atlas/autopull.env")
    tok=env.get("STATUS_TOKEN") or os.environ.get("STATUS_TOKEN"); repo=env.get("STATUS_REPO") or "cloudwalker171/atlas-manifests"
    br="main"; api="https://api.github.com"; path="status/hetzner/geo-rank.json"
    if tok and repo:
        url="%s/repos/%s/contents/%s"%(api,repo,path); sha=None
        try:
            r=urllib.request.Request(url+"?ref="+br,headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); sha=json.load(urllib.request.urlopen(r,timeout=20)).get("sha")
        except Exception: sha=None
        body={"message":"geo_rank","content":base64.b64encode(json.dumps(out,indent=2,default=str).encode()).decode(),"branch":br}
        if sha: body["sha"]=sha
        for _ in range(4):
            try:
                rq=urllib.request.Request(url,data=json.dumps(body).encode(),method="PUT",headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas","Content-Type":"application/json"}); urllib.request.urlopen(rq,timeout=25); break
            except urllib.error.HTTPError as e:
                if e.code==409:
                    try:
                        rq2=urllib.request.Request(url+"?ref="+br,headers={"Authorization":"Bearer "+tok,"Accept":"application/vnd.github+json","User-Agent":"atlas"}); body["sha"]=json.load(urllib.request.urlopen(rq2,timeout=20)).get("sha")
                    except Exception: pass
                else: break
            except Exception: time.sleep(2)
except Exception: pass
sys.exit(0)
